// Fetch the remote hub config on page load (or at build).
// The dashboard's Website → Customize tab edits this.
const res = await fetch(
  "https://dashboard.all-ai-network.org/api/v1/config",
  { headers: { Authorization: `Bearer ${process.env.AAIN_API_KEY}` } }
);
const { config } = await res.json();

// Theme: apply as CSS custom properties
document.documentElement.style.setProperty("--primary", config.theme.primary);
document.documentElement.style.setProperty("--accent",  config.theme.accent);

// Logo: point the header <img> at the uploaded URL (or fall back)
if (config.logo_url) {
  document.querySelector("#site-logo")?.setAttribute("src", config.logo_url);
}

// Sections: hide anything toggled off
for (const [name, on] of Object.entries(config.sections)) {
  if (!on) document.querySelector(`[data-section="${name}"]`)?.remove();
}

