// Fetch the top 10 members by XP
const res = await fetch(
  "https://dashboard.all-ai-network.org/api/v1/leaderboard?limit=10",
  {
    headers: { Authorization: `Bearer ${process.env.AAIN_API_KEY}` },
  }
);
const { leaderboard } = await res.json();

leaderboard.forEach((row) => {
  console.log(`#${row.rank} ${row.name} — ${row.points} XP`);
});

// Fetch chapter metadata + headline stats
const res = await fetch(
  "https://dashboard.all-ai-network.org/api/v1/chapter",
  {
    headers: { Authorization: `Bearer ${process.env.AAIN_API_KEY}` },
  }
);
const { chapter } = await res.json();

// e.g. "500 members · 142 events run"
document.querySelector("#chapter-stats").textContent =
  `${chapter.member_count} members · ${chapter.event_count} events run`;

// Pull every badge your chapter offers, sorted by creation order
const res = await fetch(
  "https://dashboard.all-ai-network.org/api/v1/badges",
  {
    headers: { Authorization: `Bearer ${process.env.AAIN_API_KEY}` },
  }
);
const { badges } = await res.json();

// `icon` is either a built-in key ("trophy", "award", ...) OR a full
// https URL to a custom image uploaded through the dashboard. Detect
// the URL case and render <img> for it; otherwise pick a local SVG.
badges.forEach((b) => {
  const isCustom = typeof b.icon === "string" && b.icon.startsWith("http");
  console.log(b.name, isCustom ? "(custom image)" : `(built-in: ${b.icon})`, `${b.award_count} earned`);
});

