snippets.javascript:
// Pull the active merch catalog for this chapter
const res = await fetch(
  "https://dashboard.all-ai-network.org/api/v1/merch",
  {
    headers: { Authorization: `Bearer ${process.env.AAIN_API_KEY}` },
  }
);
const { merch } = await res.json();

// stock === null  → unlimited  (stickers, digital rewards, etc.)
// stock === 0     → out of stock — still list it but mark it clearly
// stock  >  0     → finite supply remaining
merch.forEach((item) => {
  const stockLabel =
    item.stock === null ? "Unlimited" :
    item.stock === 0   ? "Out of stock" :
    `${item.stock} left`;
  console.log(`${item.name} — ${item.cost_points} pts · ${stockLabel}`);
});
